steps.script:
// Selector for the deep thinking toggle button (verbatim from annotation)
const deepThinkSelector = 'div.ThinkSelector_iconContainer__5HMzp.ThinkSelector_allIcon__Ndq_t';

// Check if deep thinking is already enabled by looking for the 'selected' class
const deepThinkEl = await $(deepThinkSelector);
const isEnabled = deepThinkEl.className.includes('ThinkSelector_selected__YUTmh');

if (!isEnabled) {
  // Click to enable deep thinking mode
  await $click(deepThinkSelector);
  // Wait a moment for the UI to update
  await new Promise(r => setTimeout(r, 1500));

  // Verify it's now enabled
  const verifyEl = await $(deepThinkSelector);
  const nowEnabled = verifyEl.className.includes('ThinkSelector_selected__YUTmh');
  if (!nowEnabled) {
    return { done: false };
  }
}

return { done: true, deepThinkingEnabled: true };

// Step 2: Type the question into the input area and click submit
// Use the exact annotated selector for the contenteditable input area
const inputSelector = 'div.style__text-area__edit___BKkcb';
const submitSelector = '#yuanbao-send-btn';

// Type the question from external input
await $type(inputSelector, __input__.question);

// Brief delay to ensure the input is registered and the send button becomes active
await new Promise(r => setTimeout(r, 1000));

// Click the submit button
await $click(submitSelector);

// Wait a moment for the submission to be processed
await new Promise(r => setTimeout(r, 2000));

// Verify submission happened - check that the input area is cleared or a response area appeared
const inputEl = await $exists(inputSelector, 3000);
let inputText = '';
if (inputEl) {
  try {
    inputText = await $extract(inputSelector, 'textContent', 3000);
  } catch(e) {
    // If extraction fails, assume it was cleared
  }
}

// If the input still contains the question text, the submission may not have worked
if (inputText && inputText.trim().length > 0 && inputText.trim() === String(__input__.question).trim()) {
  // Retry: click submit again
  await $click(submitSelector);
  await new Promise(r => setTimeout(r, 2000));
}

return {
  submitted: true,
  question: __input__.question
};

// Step 3: Wait for AI response to complete by polling for the annotated completion signal
// The annotated selector targets the 'Repeat' (重新生成) icon in the toolbar of the latest AI response
// This icon only appears after the AI finishes generating its response

// Wait 3 seconds before first check to allow response to start streaming
await new Promise(r => setTimeout(r, 3000));

// Check if the completion signal (Repeat icon) has appeared
const done = await $exists('div:nth-of-type(1) > div > div.yb-layout.agent-layout > div.yb-layout__content.agent-layout__content:nth-of-type(5) > div.agent-dialogue > div.agent-dialogue__content-wrapper > div.agent-dialogue__content:nth-of-type(1) > div.SplitPane.agent-dialogue__content-split-pane > div.Pane.vertical:nth-of-type(1) > div.agent-dialogue__content--common.agent-dialogue__content--common-not-speaking > div.agent-dialogue__content--common__content:nth-of-type(2) > div.agent-chat__list.agent-chat__list__hunyuan > div.agent-chat__list__content-wrapper:nth-of-type(2) > div.agent-chat__list__content:nth-of-type(2) > div.agent-chat__list__item.agent-chat__list__item--ai:nth-of-type(3) > div.agent-chat__list__item__content > div.agent-chat__bubble.agent-chat__bubble--ai:nth-of-type(2) > div.agent-chat__bubble__content > div.agent-chat__conv--ai__toolbar:nth-of-type(2) > div.agent-chat__toolbar.agent-chat__toolbar_new:nth-of-type(2) > div.agent-chat__toolbar__right:nth-of-type(2) > div:nth-of-type(5) > div.Repeat_icon__oL8u_.Repeat_with-hover__PDJ30 > span.yb-icon.iconfont-yb', 5000);

if (done) {
  // Also verify content stability - ensure the answer text is not still streaming
  // Use a broader selector for the AI response content to check stability
  const stable = await $waitForStable('.agent-chat__list__item--last .hyc-content-md-done', {
    interval: 1500,
    stableChecks: 2,
    maxMs: 15000
  });

  if (stable) {
    return { done: true };
  }
  return { done: false };
}

return { done: false };

// Extract thinking process using the annotated selector
let thinking = '';
try {
  thinking = await $extract('div.agent-chat__list__item--ai.agent-chat__list__item--last div.hyc-component-deepsearch-cot__think__content div.hyc-common-markdown.hyc-common-markdown-style', undefined, 5000);
} catch (e) {
  thinking = '';
}

// Extract answer using the annotated selector
let answer = '';
try {
  answer = await $extract('div.agent-chat__list__item--ai.agent-chat__list__item--last div.hyc-component-deepsearch-cot > div.hyc-content-md.hyc-content-md-done:nth-of-type(2) > div.hyc-common-markdown.hyc-common-markdown-style', undefined, 5000);
} catch (e) {
  answer = '';
}

// If answer is empty, try a broader selector for the answer content
if (!answer) {
  try {
    answer = await $extract('div.agent-chat__list__item--ai.agent-chat__list__item--last div.hyc-component-deepsearch-cot > div.hyc-content-md.hyc-content-md-done:last-child > div.hyc-common-markdown.hyc-common-markdown-style', undefined, 5000);
  } catch (e2) {
    answer = '';
  }
}

// Validate extraction - retry if both are empty
if (!thinking && !answer) {
  return { done: false };
}

return {
  thinking: thinking || '',
  answer: answer || '',
  question: __input__.question || ''
};

const result = __lastResult__;

return {
  question: result.question || __input__.question,
  thinking: result.thinking || '',
  answer: result.answer || ''
};
